        simp [ih, ih']
        <;> try { 
          simp_all [hf, h2]
        }
      | is_zero e k cr ih' =>
        simp [ih, ih']
        <;> try { 
          simp_all [hf, h2]
        }
      | assert_range w e k cr ih' =>
        simp [ih, ih']
        <;> try { 
          simp_all [hf, h2]
        }
  simp_all [h3]

